import React from "react";
import ReactDOM from "react-dom/client";
import App from "./App";
import { ProgressProvider } from "./context/ProgressContext";

const root = ReactDOM.createRoot(document.getElementById("root"));

root.render(
  <ProgressProvider>
    <App />
  </ProgressProvider>
);
